import React, { useState } from "react";

import { Box } from "../Box";
import { Stack } from "../Stack";
import { Tabs } from "./Tabs";
import { Text } from "../Text";

export default {
  title: "Navigation/Tabs",
  component: Tabs,
  tags: ["autodocs"],
  parameters: {
    docs: {
      description: {
        component:
          "Tabs component for organizing content into separate views where only one view is visible at a time.",
      },
    },
  },
  argTypes: {
    variant: {
      control: "select",
      options: ["line", "enclosed", "outline", "plain"],
      description: "Visual variant of the tabs",
    },
    size: {
      control: "select",
      options: ["sm", "md", "lg"],
      description: "Size of the tabs",
    },
    orientation: {
      control: "select",
      options: ["horizontal", "vertical"],
      description: "Orientation of the tabs",
    },
    fitted: {
      control: "boolean",
      description: "Whether tabs should stretch to fill container",
    },
  },
};

export const Default = () => (
  <Tabs defaultValue="tab1">
    <Tabs.List>
      <Tabs.Trigger value="tab1">Account</Tabs.Trigger>
      <Tabs.Trigger value="tab2">Security</Tabs.Trigger>
      <Tabs.Trigger value="tab3">Notifications</Tabs.Trigger>
    </Tabs.List>
    <Tabs.Content value="tab1">
      <Box p={4}>
        <Text>Manage your account settings and preferences.</Text>
      </Box>
    </Tabs.Content>
    <Tabs.Content value="tab2">
      <Box p={4}>
        <Text>Configure your security and privacy settings.</Text>
      </Box>
    </Tabs.Content>
    <Tabs.Content value="tab3">
      <Box p={4}>
        <Text>Manage your notification preferences.</Text>
      </Box>
    </Tabs.Content>
  </Tabs>
);

